// Family Workshop — landing-page search + filter logic.
//
// Loads ./projects.json (auto-generated by .github/workflows/build-index.yml
// from each project's meta.json), renders cards, filters live as the user
// types or toggles chips. URL state is mirrored in the query string so a
// filtered view can be shared.

const SUBJECT_LABELS = {
  astronomie: 'Astronomie',
  physik:     'Physik',
  mathe:      'Mathe',
  biologie:   'Biologie',
  chemie:     'Chemie',
  sprache:    'Sprache',
  musik:      'Musik',
  geschichte: 'Geschichte',
  kunst:      'Kunst',
  technik:    'Technik',
};

const AGE_LABELS = {
  '3-5':  '3–5 J.',
  '6-8':  '6–8 J.',
  '9-12': '9–12 J.',
  '13+':  '13+ J.',
};

const LANG_LABELS = {
  de: '🇩🇪 Deutsch',
  en: '🇬🇧 English',
};

const grid = document.getElementById('grid');
const tpl = document.getElementById('card-tpl');
const qInput = document.getElementById('q');
const countEl = document.getElementById('count');
const resetBtn = document.getElementById('reset');

const state = {
  projects: [],
  q: '',
  subject: new Set(),
  age: new Set(),
  language: new Set(),
};

// ── Boot ──────────────────────────────────────────────────────────────

(async function init() {
  try {
    const res = await fetch('./projects.json', { cache: 'no-cache' });
    if (!res.ok) throw new Error(`projects.json HTTP ${res.status}`);
    const data = await res.json();
    state.projects = (data.projects || []).slice().sort((a, b) =>
      (b.created_at || '').localeCompare(a.created_at || ''));
  } catch (err) {
    grid.innerHTML = `
      <div class="empty">
        <strong>Konnte den Katalog nicht laden.</strong>
        <code>projects.json</code> ist noch nicht da. Push das Repo, damit die GitHub-Action sie generiert.
      </div>`;
    countEl.textContent = '';
    console.warn(err);
    return;
  }
  buildFilters();
  hydrateFromUrl();
  bindEvents();
  render();
})();

// ── Filters from data ─────────────────────────────────────────────────

function buildFilters() {
  const subjects = new Set();
  const ages = new Set();
  const langs = new Set();
  for (const p of state.projects) {
    (p.subjects || []).forEach(s => subjects.add(s));
    (p.ages || []).forEach(a => ages.add(a));
    if (p.language) langs.add(p.language);
  }

  fillFilter('filter-subject', sortByLabel(subjects, SUBJECT_LABELS), 'subject');
  fillFilter('filter-age',     sortAges(ages),                         'age');
  fillFilter('filter-language', sortByLabel(langs, LANG_LABELS),       'language');
}

function fillFilter(fieldsetId, values, key) {
  const fs = document.getElementById(fieldsetId);
  for (const v of values) {
    const label = (key === 'subject' ? SUBJECT_LABELS[v] :
                   key === 'age'     ? AGE_LABELS[v] :
                   key === 'language'? LANG_LABELS[v] : v) || v;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'chip';
    btn.dataset.key = key;
    btn.dataset.value = v;
    btn.textContent = label;
    btn.addEventListener('click', () => toggleChip(btn));
    fs.appendChild(btn);
  }
  if (!values.length) fs.style.display = 'none';
}

function sortByLabel(set, labels) {
  return [...set].sort((a, b) => (labels[a] || a).localeCompare(labels[b] || b, 'de'));
}
function sortAges(set) {
  const order = ['3-5', '6-8', '9-12', '13+'];
  return [...set].sort((a, b) => order.indexOf(a) - order.indexOf(b));
}

function toggleChip(btn) {
  const { key, value } = btn.dataset;
  const set = state[key];
  if (set.has(value)) { set.delete(value); btn.classList.remove('active'); }
  else { set.add(value); btn.classList.add('active'); }
  render();
  syncUrl();
}

// ── Filtering ─────────────────────────────────────────────────────────

function matches(p) {
  if (state.q) {
    const hay = [p.title, p.summary, ...(p.tags || [])].join(' ').toLowerCase();
    if (!hay.includes(state.q.toLowerCase())) return false;
  }
  if (state.subject.size && !(p.subjects || []).some(s => state.subject.has(s))) return false;
  if (state.age.size     && !(p.ages || []).some(a => state.age.has(a))) return false;
  if (state.language.size && !state.language.has(p.language)) return false;
  return true;
}

function render() {
  const matched = state.projects.filter(matches);
  grid.innerHTML = '';
  for (const p of matched) {
    const node = tpl.content.firstElementChild.cloneNode(true);
    node.href = p.url || `./${p.slug}/`;
    node.querySelector('.card-title').textContent = p.title;
    node.querySelector('.card-summary').textContent = p.summary || '';
    const lang = node.querySelector('.lang');
    lang.textContent = p.language === 'de' ? '🇩🇪' : p.language === 'en' ? '🇬🇧' : '';
    lang.title = LANG_LABELS[p.language] || '';
    node.querySelector('.ages').textContent = (p.ages || []).join(' · ');
    const tagsUl = node.querySelector('.card-tags');
    for (const t of (p.tags || [])) {
      const li = document.createElement('li');
      li.textContent = t;
      tagsUl.appendChild(li);
    }
    grid.appendChild(node);
  }

  if (!matched.length) {
    grid.innerHTML = `<div class="empty">
      <strong>Nichts gefunden.</strong>
      Such was anderes oder nimm die Filter raus.
    </div>`;
  }

  countEl.textContent = matched.length === state.projects.length
    ? `${matched.length} ${matched.length === 1 ? 'Projekt' : 'Projekte'} insgesamt`
    : `${matched.length} von ${state.projects.length} Projekten`;
  resetBtn.disabled = !hasActiveFilter();
}

function hasActiveFilter() {
  return !!state.q || state.subject.size || state.age.size || state.language.size;
}

// ── URL state ─────────────────────────────────────────────────────────

function hydrateFromUrl() {
  const params = new URLSearchParams(location.search);
  state.q = params.get('q') || '';
  qInput.value = state.q;
  for (const key of ['subject', 'age', 'language']) {
    const raw = params.get(key);
    if (!raw) continue;
    raw.split(',').filter(Boolean).forEach(v => state[key].add(v));
  }
  // mark chips active to match
  document.querySelectorAll('.chip').forEach(c => {
    if (state[c.dataset.key]?.has(c.dataset.value)) c.classList.add('active');
  });
}

function syncUrl() {
  const params = new URLSearchParams();
  if (state.q) params.set('q', state.q);
  for (const key of ['subject', 'age', 'language']) {
    if (state[key].size) params.set(key, [...state[key]].join(','));
  }
  const qs = params.toString();
  history.replaceState(null, '', qs ? `?${qs}` : location.pathname);
}

// ── Events ────────────────────────────────────────────────────────────

function bindEvents() {
  let t;
  qInput.addEventListener('input', e => {
    state.q = e.target.value.trim();
    clearTimeout(t);
    t = setTimeout(() => { render(); syncUrl(); }, 80);
  });
  resetBtn.addEventListener('click', () => {
    state.q = '';
    qInput.value = '';
    state.subject.clear();
    state.age.clear();
    state.language.clear();
    document.querySelectorAll('.chip.active').forEach(c => c.classList.remove('active'));
    render();
    syncUrl();
  });
}
